import utility
import matplotlib.pyplot as plt


def plot(xs, ys, legend, fname):
    fig, ax = plt.subplots(figsize=(6.4, 3.6))

    for x, y in zip(xs, ys):
        ax.plot(x, y)

    ax.set_xlim(0, 1)
    
    ax.set_xlabel("$t$")
    ax.set_ylabel("$E$")
    ax.grid()
    ax.legend(legend)

    fig.tight_layout(pad=0.2)
    fig.savefig(fname, transparent=True)

    plt.close()


